float pgain( long x, Points *points, float z, long int *numcenters, int kmax, bool *is_center_arr, int *center_table_arr, bool *switch_membership_arr, bool isCoordChangedFlag,
             double *serial_t_acc, double *cpu_to_gpu_t_acc, double *gpu_to_cpu_t_acc, double *alloc_t_acc, double *kernel_t_acc, double *free_t_acc)
{
  double t0 = gettime();

  int stride = *numcenters + 1;
  int K = *numcenters;
  int num = points->num;
  int dim = points->dim;
  int nThread = num;

  work_mem_h = (float*) malloc(stride * (nThread + 1) * sizeof(float));

  if(iter == 0) {
    allocHostMem(num, dim);
  }

  int count = 0;
  for(int i=0; i<num; i++) {
    if(is_center_arr[i]) {
      center_table_arr[i] = count++;
    }
  }

  if(isCoordChangedFlag || iter == 0) {
    for(int i=0; i<dim; i++) {
      for(int j=0; j<num; j++) {
        coord_h[(num*i)+j] = points->p[j].coord[i];
      }
    }
  }

  *serial_t_acc += (gettime() - t0) * 1000.0;
  t0 = gettime();

  work_mem_d = (float*) malloc(stride * (nThread + 1) * sizeof(float));
  if(iter == 0) {
    allocDevMem(num, dim);
  }

  *alloc_t_acc += (gettime() - t0) * 1000.0;
  t0 = gettime();

  if(isCoordChangedFlag || iter == 0) {
    memcpy(coord_d, coord_h, num * dim * sizeof(float));
  }
  memcpy(center_table_d, center_table_arr, num * sizeof(int));
  memcpy(p_d, points->p, num * sizeof(Point));
  memset(switch_membership_d, 0, num * sizeof(bool));
  memset(work_mem_d, 0, stride * (nThread + 1) * sizeof(float));

  *cpu_to_gpu_t_acc += (gettime() - t0) * 1000.0;
  t0 = gettime();

  #pragma omp parallel for schedule(static)
  for(int tid = 0; tid < num; tid++) {
    float *lower = &work_mem_d[tid*stride];
    float x_cost = d_dist(tid, (int)x, num, dim, coord_d) * p_d[tid].weight;
    if (x_cost < p_d[tid].cost) {
      switch_membership_d[tid] = 1;
      lower[K] += x_cost - p_d[tid].cost;
    } else {
      lower[center_table_d[p_d[tid].assign]] += p_d[tid].cost - x_cost;
    }
  }

  *kernel_t_acc += (gettime() - t0) * 1000.0;
  t0 = gettime();

  memcpy(work_mem_h, work_mem_d, stride * (nThread + 1) * sizeof(float));
  memcpy(switch_membership_arr, switch_membership_d, num * sizeof(bool));

  *gpu_to_cpu_t_acc += (gettime() - t0) * 1000.0;
  t0 = gettime();

  int number_of_centers_to_close = 0;
  float gl_cost_of_opening_x = z;
  float *gl_lower = &work_mem_h[stride * nThread];

  for(int i=0; i<num; i++) {
    if(is_center_arr[i]) {
      float low = z;
      for(int j=0; j<num; j++) {
        low += work_mem_h[j*stride + center_table_arr[i]];
      }
      gl_lower[center_table_arr[i]] = low;
      if(low > 0) {
        ++number_of_centers_to_close;
        work_mem_h[i*stride + K] -= low;
      }
    }
    gl_cost_of_opening_x += work_mem_h[i*stride + K];
  }

  if (0 > gl_cost_of_opening_x) {
    for(int i=0; i<num; i++) {
      bool close_center = gl_lower[center_table_arr[points->p[i].assign]] > 0;
      if (switch_membership_arr[i] || close_center) {
        points->p[i].cost = dist(points->p[i], points->p[x], dim) * points->p[i].weight;
        points->p[i].assign = x;
      }
    }

    for(int i=0; i<num; i++) {
      if(is_center_arr[i] && 0 < gl_lower[center_table_arr[i]]) {
        is_center_arr[i] = false;
      }
    }

    if(0 <= x && x < num) {
      is_center_arr[x] = true;
    }
    *numcenters = *numcenters + 1 - number_of_centers_to_close;
  } else {
    gl_cost_of_opening_x = 0;
  }

  free(work_mem_h);
  work_mem_h = NULL;

  *serial_t_acc += (gettime() - t0) * 1000.0;
  t0 = gettime();

  free(work_mem_d);
  work_mem_d = NULL;

  *free_t_acc += (gettime() - t0) * 1000.0;

  iter++;
  return -gl_cost_of_opening_x;
}

